module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [WIDTH-1:0] ram [DEPTH-1:0];
wire [ADDR_WIDTH-1:0] waddr, raddr;
wire [WIDTH-1:0] rdata_ram;

always @(posedge wclk) begin
    if (winc && !wfull) begin
        ram[waddr] <= wdata;
    end
end

always @(posedge rclk) begin
    if (rinc && !rempty) begin
        rdata <= ram[raddr];
    end
end

reg [ADDR_WIDTH:0] wptr;
reg [ADDR_WIDTH:0] wptr_gray;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr <= 0;
        wptr_gray <= 0;
    end else if (winc && !wfull) begin
        wptr <= wptr + 1;
        wptr_gray <= (wptr + 1) ^ (wptr + 1) >> 1;
    end
end

reg [ADDR_WIDTH:0] rptr;
reg [ADDR_WIDTH:0] rptr_gray;

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr <= 0;
        rptr_gray <= 0;
    end else if (rinc && !rempty) begin
        rptr <= rptr + 1;
        rptr_gray <= (rptr + 1) ^ (rptr + 1) >> 1;
    end
end

reg [ADDR_WIDTH:0] rptr_sync1, rptr_sync2;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        rptr_sync1 <= 0;
        rptr_sync2 <= 0;
    end else begin
        rptr_sync1 <= rptr_gray;
        rptr_sync2 <= rptr_sync1;
    end
end

reg [ADDR_WIDTH:0] wptr_sync1, wptr_sync2;

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        wptr_sync1 <= 0;
        wptr_sync2 <= 0;
    end else begin
        wptr_sync1 <= wptr_gray;
        wptr_sync2 <= wptr_sync1;
    end
end

assign rempty = (wptr_sync2 == rptr);
assign wfull = (wptr[ADDR_WIDTH] != rptr[ADDR_WIDTH]) && (wptr[ADDR_WIDTH-1:0] == rptr[ADDR_WIDTH-1:0]);

assign waddr = wptr[ADDR_WIDTH-1:0];
assign raddr = rptr_sync2[ADDR_WIDTH-1:0];

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
